"AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Advanced Illness (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Advanced Illness (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS AdvancedIllnessDiagnosis WHERE AdvancedIllnessDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(AdvancedIllnessDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(AdvancedIllnessDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(AdvancedIllnessDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetDateTime'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(AdvancedIllnessDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)))
),
"AIFrailLTCF.Has Criteria Indicating Frailty" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "DeviceRequest: Frailty Device" WHERE fhirpath_text(resource, 'status') IN ('active', 'completed') AND fhirpath_text(resource, 'intent') IN ('order', 'original-order', 'reflex-order', 'filler-order', 'instance-order')) AS FrailtyDeviceOrder WHERE FrailtyDeviceOrder.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn')), '{') THEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') ELSE intervalFromBounds(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), TRUE, TRUE) END) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn')), '{') THEN fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn') ELSE intervalFromBounds(fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), fhirpath_text(FrailtyDeviceOrder.resource, 'authoredOn'), TRUE, TRUE) END) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Medical equipment used" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS EquipmentUsed WHERE EquipmentUsed.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(EquipmentUsed.resource::JSON, '$.valueCodeableConcept.coding'), '["JSON"]'),from_json(json_extract(EquipmentUsed.resource::JSON, '$.value.coding'), '["JSON"]'),CAST([] AS JSON[]))) AS _c) _inv INNER JOIN _vs_20 ON _vs_20._vs_code = json_extract_string(_c, '$.code') AND (_vs_20._vs_system = '' OR _vs_20._vs_system = json_extract_string(_c, '$.system'))) AND CAST(intervalEnd(CASE WHEN fhirpath_text(EquipmentUsed.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(EquipmentUsed.resource, 'effective')), '{') THEN fhirpath_text(EquipmentUsed.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(EquipmentUsed.resource, 'effective'), fhirpath_text(EquipmentUsed.resource, 'effective'), TRUE, TRUE) END) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Frailty Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Frailty Diagnosis (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS FrailtyDiagnosis WHERE FrailtyDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(FrailtyDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(FrailtyDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')), fhirpath_text(FrailtyDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(FrailtyDiagnosis.resource, 'onsetDateTime'), fhirpath_text(FrailtyDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(FrailtyDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from