d, resource FROM "Observation: Frailty Symptom" WHERE fhirpath_text(resource, 'status') IN ('preliminary', 'final', 'amended', 'corrected')) AS FrailtySymptom WHERE FrailtySymptom.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(FrailtySymptom.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtySymptom.resource, 'effective')), '{') THEN fhirpath_text(FrailtySymptom.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FrailtySymptom.resource, 'effective'), fhirpath_text(FrailtySymptom.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(FrailtySymptom.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(FrailtySymptom.resource, 'effective')), '{') THEN fhirpath_text(FrailtySymptom.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(FrailtySymptom.resource, 'effective'), fhirpath_text(FrailtySymptom.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
