),
"AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 66 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Dementia Medications in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id))
),
"AIFrailLTCF.Is Age 66 to 80 with Advanced Illness and Frailty or Is Age 81 or Older with Frailty" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END BETWEEN 66 AND 80 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Dementia Medications in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)) OR EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHER