),
"Essential Hypertension Diagnosis" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Essential Hypertension (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Essential Hypertension (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS Hypertension WHERE intervalOverlaps(CASE WHEN fhirpath_text(Hypertension.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')), fhirpath_text(Hypertension.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(Hypertension.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(Hypertension.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(dateAddQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, FALSE))
),
"Initial Population" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END BETWEEN 18 AND 85 AND EXISTS (SELECT 1 FROM "Essential Hypertension Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "AdultOutpatientEncounters.Qualifying Encounters" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS MATERIALIZED (
SELECT * FROM "Initial Population"
),
"Pregnancy or Renal Diagnosis" AS MATERIALIZED (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Pregnancy (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Pregnancy (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: End Stage Renal Disease (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: End Stage Renal Disease (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Kidney Transplant Recipient (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Kidney Transplant Recipient (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Chronic Kidney Disease, Stage 5 (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Chronic Kidney Disease, Stage 5 (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS PregnancyESRDDiagnosis WHERE intervalOverlaps(CASE WHEN fhirpath_text(PregnancyESRDDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')), fhirpath_text(PregnancyESRDDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PregnancyESRDDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PregnancyESRDDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE))
),
"Denominator Exclusions" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Pregnancy or Renal Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "End Stage Renal Disease Procedures" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "End Stage Renal Disease Encounter" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 to 80 with Advanced Illness and Frailty or Is Age 81 or Older with Frailty" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
),
"Qualifying Diastolic Blood Pressure Reading" AS MATERIALIZED (
(SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Encounter Inpatient" UNION SELECT patient_id, resource FROM "Encounter: Emergency Department Evaluation and Management Visit") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS DisqualifyingEncounter WHERE CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) >= CAST(intervalStart(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS DATE) AND CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND DisqualifyingEncounter.patient_id = BloodPressure.patient_id)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT array_contains(['EMER', 'IMP', 'ACUTE', 'NONAC', 'PRENC', 'SS'], fhirpath_text(CASE WHEN (SELECT COUNT(*) FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id) = 1 THEN (SELECT resource FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id LIMIT 1) ELSE NULL END, 'class.code')) AND CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE))
),
"Qualifying Systolic Blood Pressure Reading" AS MATERIALIZED (
(SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Encounter Inpatient" UNION SELECT patient_id, resource FROM "Encounter: Emergency Department Evaluation and Management Visit") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS DisqualifyingEncounter WHERE CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) >= CAST(intervalStart(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS DATE) AND CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND DisqualifyingEncounter.patient_id = BloodPressure.patient_id)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT array_contains(['EMER', 'IMP', 'ACUTE', 'NONAC', 'PRENC', 'SS'], fhirpath_text(CASE WHEN (SELECT COUNT(*) FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id) = 1 THEN (SELECT resource FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id LIMIT 1) ELSE NULL END, 'class.code')) AND CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(COALESCE(fhirpath_date(BloodPressure.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE))
),
"Blood Pressure Days" AS MATERIALIZED (
(SELECT DBPExam.patient_id, COALESCE(fhirpath_date(DBPExam.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(DBPExam.resource, 'effectivePeriod'))) AS value FROM "Qualifying Diastolic Blood Pressure Reading" AS DBPExam) INTERSECT (SELECT SBPExam.patient_id, COALESCE(fhirpath_date(SBPExam.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(SBPExam.resource, 'effectivePeriod'))) AS value FROM "Qualifying Systolic Blood Pressure Reading" AS SBPExam)
),
"Most Recent Blood Pressure Day" AS MATERIALIZED (
SELECT p.patient_id, (SELECT value FROM "Blood Pressure Days" AS BPDays WHERE BPDays.patient_id = p.patient_id ORDER BY value ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Lowest Diastolic Reading on Most Recent Blood Pressure Day" AS MATERIALIZED (
SELECT p.patient_id, (SELECT (SELECT TRY_CAST(json_extract_string(c, '$.valueQuantity.value') AS DOUBLE) FROM (SELECT unnest(COALESCE(from_json(json_extract(DBPReading.resource::JSON, '$.component'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _comp_t WHERE json_extract_string(c, '$.code.coding[0].display') = 'Diastolic blood pressure' LIMIT 1) FROM "Qualifying Diastolic Blood Pressure Reading" AS DBPReading WHERE CAST(COALESCE(fhirpath_date(DBPReading.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(DBPReading.resource, 'effectivePeriod'))) AS DATE) = CAST((SELECT sub.value FROM "Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE) AND DBPReading.patient_id = p.patient_id ORDER BY (SELECT TRY_CAST(json_extract_string(c, '$.valueQuantity.value') AS DOUBLE) FROM (SELECT unnest(COALESCE(from_json(json_extract(DBPReading.resource::JSON, '$.component'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _comp_t WHERE json_extract_string(c, '$.code.coding[0].display') = 'Diastolic blood pressure' LIMIT 1) ASC NULLS LAST, json_extract_string(DBPReading.resource, '$.id') ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Has Diastolic Blood Pressure Less Than 90" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE (SELECT sub.value FROM "Lowest Diastolic Reading on Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) < 90.0
),
"Lowest Systolic Reading on Most Recent Blood Pressure Day" AS MATERIALIZED (
SELECT p.patient_id, (SELECT (SELECT TRY_CAST(json_extract_string(c, '$.valueQuantity.value') AS DOUBLE) FROM (SELECT unnest(COALESCE(from_json(json_extract(SBPReading.resource::JSON, '$.component'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _comp_t WHERE json_extract_string(c, '$.code.coding[0].display') = 'Systolic blood pressure' LIMIT 1) FROM "Qualifying Systolic Blood Pressure Reading" AS SBPReading WHERE CAST(COALESCE(fhirpath_date(SBPReading.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(SBPReading.resource, 'effectivePeriod'))) AS DATE) = CAST((SELECT sub.value FROM "Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS DATE) AND SBPReading.patient_id = p.patient_id ORDER BY (SELECT TRY_CAST(json_extract_string(c, '$.valueQuantity.value') AS DOUBLE) FROM (SELECT unnest(COALESCE(from_json(json_extract(SBPReading.resource::JSON, '$.component'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _comp_t WHERE json_extract_string(c, '$.code.coding[0].display') = 'Systolic blood pressure' LIMIT 1) ASC NULLS LAST, json_extract_string(SBPReading.resource, '$.id') ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Has Systolic Blood Pressure Less Than 140" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE (SELECT sub.value FROM "Lowest Systolic Reading on Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) < 140.0
),
"Numerator" AS MATERIALIZED (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Systolic Blood Pressure Less Than 140" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Has Diastolic Blood Pressure Less Than 90" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS MATERIALIZED (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, "Initial Population".patient_id IS NOT NULL AS "Initial Population", "Denominator".patient_id IS NOT NULL AND "Initial Population".patient_id IS NOT NULL AS Denominator, "Denominator Exclusions".patient_id IS NOT NULL AS "Denominator Exclusions", "Numerator".patient_id IS NOT NULL AND "Initial Population".patient_id IS NOT NULL AND "Denominator Exclusions".patient_id IS NULL AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
